import{_ as e,c as d,o as r,ae as i}from"./chunks/framework.CDjunVez.js";const c=JSON.parse('{"title":"Introduction","description":"","frontmatter":{},"headers":[],"relativePath":"introduction/about.md","filePath":"introduction/about.md"}'),a={name:"introduction/about.md"};function o(n,t,s,l,u,p){return r(),d("div",null,[...t[0]||(t[0]=[i('<h1 id="introduction" tabindex="-1">Introduction <a class="header-anchor" href="#introduction" aria-label="Permalink to &quot;Introduction&quot;">​</a></h1><h2 id="kiwipanel" tabindex="-1">KiwiPanel <a class="header-anchor" href="#kiwipanel" aria-label="Permalink to &quot;KiwiPanel&quot;">​</a></h2><p>⚠️ <strong>WARNING: PRE-ALPHA RELEASE — DO NOT DEPLOY TO PRODUCTION</strong></p><p>KiwiPanel is a lightweight, open-source server control panel focused on <strong>simplicity, transparency, and sane defaults</strong>.</p><p>It is designed to help you manage a <strong>LOMP stack</strong> (Linux, OpenLiteSpeed, MariaDB, PHP) without bloat or lock-in.</p><h2 id="built-for-developers-vps-users" tabindex="-1">Built for Developers &amp; VPS Users <a class="header-anchor" href="#built-for-developers-vps-users" aria-label="Permalink to &quot;Built for Developers &amp; VPS Users&quot;">​</a></h2><p>KiwiPanel is written primarily in <strong>Go</strong>, with a strong emphasis on:</p><ul><li>Minimal resource usage</li><li>Clear system visibility</li><li>Scriptable and inspectable behavior</li><li>Clean separation between the panel and the server stack</li></ul><p>It is designed for:</p><ul><li>Developers who want full visibility into how their server works</li><li>VPS users who prefer lightweight tooling over heavy abstractions</li><li>System administrators who value reproducibility, auditability, and control</li></ul><h2 id="feature-comparison" tabindex="-1">Feature Comparison <a class="header-anchor" href="#feature-comparison" aria-label="Permalink to &quot;Feature Comparison&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Category</th><th>Feature</th><th>KiwiPanel</th><th>aaPanel</th><th>CloudPanel</th><th>CyberPanel</th><th>FastPanel</th></tr></thead><tbody><tr><td><strong>Users</strong></td><td>Admin user</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td></tr><tr><td></td><td>Client users</td><td>✅</td><td>✅</td><td>❌</td><td>✅</td><td>✅</td></tr><tr><td></td><td>User isolation</td><td>🔒 Per-user</td><td>🔒 Per-user</td><td>🔒 Subscription</td><td>🔒 Per-user</td><td>🔒 Per-user</td></tr><tr><td><strong>Web</strong></td><td>Web server</td><td>OpenLiteSpeed</td><td>Nginx / Apache / OLS</td><td>Nginx</td><td>OpenLiteSpeed</td><td>Nginx</td></tr><tr><td></td><td>Multiple PHP versions</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td></tr><tr><td></td><td>Per-site config</td><td>✅</td><td>⚠️ Limited</td><td>✅</td><td>⚠️ Limited</td><td>✅</td></tr><tr><td><strong>Security</strong></td><td>Firewall UI</td><td>❌</td><td>✅</td><td>✅</td><td>❌</td><td>✅</td></tr><tr><td></td><td>Malware scan</td><td>Planned</td><td>✅</td><td>❌</td><td>⚠️ Limited</td><td>❌</td></tr><tr><td></td><td>Auto SSL</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td></tr></tbody></table>',12)])])}const P=e(a,[["render",o]]);export{c as __pageData,P as default};
